package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;

public class CSVFormatTest {

    @Test
    public void testGetNullString_Default() {
        CSVFormat format = CSVFormat.DEFAULT;
        assertNull(format.getNullString(), "Default CSVFormat nullString should be null");
    }

    @Test
    public void testGetNullString_MySQL() {
        CSVFormat format = CSVFormat.MYSQL;
        assertEquals("\\N", format.getNullString(), "MYSQL CSVFormat nullString should be '\\N'");
    }

    @Test
    public void testGetNullString_CustomWithNull() {
        CSVFormat format = CSVFormat.DEFAULT.withNullString(null);
        assertNull(format.getNullString(), "Custom CSVFormat with null nullString should return null");
    }

    @Test
    public void testGetNullString_CustomWithValue() {
        String nullStr = "NULL";
        CSVFormat format = CSVFormat.DEFAULT.withNullString(nullStr);
        assertEquals(nullStr, format.getNullString(), "Custom CSVFormat with nullString should return the set value");
    }
}
